SELECT station_name
FROM traffic_stations
WHERE location = 'New York City';

SELECT traffic_stations.station_name, sensors.sensor_type, sensors.description
FROM traffic_stations
INNER JOIN sensors ON traffic_stations.station_id = sensors.station_id;

SELECT station_name, status 
FROM traffic_stations 
WHERE station_name = 'Station A';

SELECT station_name, location, latitude, longitude, status
FROM traffic_stations
WHERE station_id = 0;

SELECT location, COUNT(station_id) AS number_of_stations
FROM traffic_stations
GROUP BY location;

SELECT *
FROM traffic_camera_feeds
WHERE status <> 'active';

SELECT station_name, location
FROM traffic_stations
ORDER BY station_name;
